ALGORITHM CUDA_Thread_Indexing
INPUT: blockIdx, blockDim, threadIdx, gridDim
OUTPUT: global_index (for various dimensions)

// ============================================
// 1D INDEXING ALGORITHM
// ============================================
FUNCTION Compute_1D_Index(blockIdx_x, blockDim_x, threadIdx_x)
 global_index = blockIdx_x * blockDim_x + threadIdx_x
 RETURN global_index
END FUNCTION

// ============================================
// 2D INDEXING ALGORITHM (Matrix/Image Processing)
// ============================================
FUNCTION Compute_2D_Index(blockIdx_x, blockIdx_y, blockDim_x, blockDim_y, threadIdx_x, threadIdx_y, width)
 // Compute column and row within the matrix
 col = blockIdx_x * blockDim_x + threadIdx_x
 row = blockIdx_y * blockDim_y + threadIdx_y

 // Convert 2D coordinate to 1D linear index
 global_index = row * width + col
 RETURN global_index, col, row
END FUNCTION

// ============================================
// 3D INDEXING ALGORITHM (Volumetric Data)
// ============================================
FUNCTION Compute_3D_Index(blockIdx_x, blockIdx_y, blockIdx_z,
 blockDim_x, blockDim_y, blockDim_z,
 threadIdx_x, threadIdx_y, threadIdx_z, width, height)
 x = blockIdx_x * blockDim_x + threadIdx_x
 y = blockIdx_y * blockDim_y + threadIdx_y
 z = blockIdx_z * blockDim_z + threadIdx_z

 // Linearize 3D coordinates to 1D array index
 global_index = z * width * height + y * width + x
 RETURN global_index, x, y, z
END FUNCTION

// ============================================
// GRID-STRIDE LOOP ALGORITHM
// ============================================
FUNCTION Grid_Stride_Loop_Process(data, N, blockIdx_x, blockDim_x, threadIdx_x)
 // Compute initial global index
 idx = blockIdx_x * blockDim_x + threadIdx_x

 // Total threads in grid
 stride = blockDim_x * gridDim.x

 // Process multiple elements per thread
 WHILE idx < N
 // Process element at index
 data[idx] = Process(data[idx])

 // Move to next element
 idx = idx + stride
 END WHILE
END FUNCTION

// ============================================
// KERNEL LAUNCH CONFIGURATION
// ============================================
FUNCTION Compute_Grid_Size(total_elements, threads_per_block)
 grid_size = (total_elements + threads_per_block - 1) / threads_per_block
 RETURN grid_size // Ceiling division
END FUNCTION

// Example usage:
// N = 10000, blockSize = 256
// gridSize = (10000 + 256 - 1) / 256 = 40 blocks

#include <stdio.h>
#include <stdlib.h>

// ============================================
// MACRO FOR CUDA ERROR CHECKING
// ============================================
#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 printf("CUDA Error: %s at %s:%d\n", \
 cudaGetErrorString(err), __FILE__, __LINE__); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// ============================================
// 1D KERNEL: Array Doubling
// ============================================
__global__ void kernel_double_array_1d(float *data, int N) {
 // Compute global thread index using 1D formula
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Boundary check: ensure we don't access beyond array
 if (idx < N) {
 data[idx] = data[idx] * 2.0f;
 }
}

// ============================================
// 2D KERNEL: Matrix Element Processing
// ============================================
__global__ void kernel_process_matrix_2d(float *matrix, int width, int height) {
 // Compute column and row indices
 int col = blockIdx.x * blockDim.x + threadIdx.x;
 int row = blockIdx.y * blockDim.y + threadIdx.y;

 // Boundary checks
 if (col < width && row < height) {
 int idx = row * width + col; // Linearize 2D to 1D
 matrix[idx] = matrix[idx] * 2.0f;
 }
}

// ============================================
// 3D KERNEL: Volumetric Data Processing
// ============================================
__global__ void kernel_process_volume_3d(float *volume, int W, int H, int D) {
 int x = blockIdx.x * blockDim.x + threadIdx.x;
 int y = blockIdx.y * blockDim.y + threadIdx.y;
 int z = blockIdx.z * blockDim.z + threadIdx.z;

 if (x < W && y < H && z < D) {
 int idx = z * W * H + y * W + x; // Linearize 3D to 1D
 volume[idx] = volume[idx] * 2.0f;
 }
}

// ============================================
// GRID-STRIDE LOOP KERNEL: Large Array Processing
// ============================================
__global__ void kernel_grid_stride_loop(float *data, int N) {
 // Compute initial global index
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Compute stride: total number of threads in grid
 int stride = blockDim.x * gridDim.x;

 // Grid-stride loop: each thread processes multiple elements
 for (int i = idx; i < N; i += stride) {
 data[i] = data[i] * 2.0f;
 }
}

// ============================================
// WARP-AWARE KERNEL: Avoiding Divergence
// ============================================
__global__ void kernel_warp_aware(float *data, int N) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 if (idx < N) {
 // Best practice: Use block-level branching, not thread-level
 // This ensures all 32 threads in a warp take the same path

 // Example: Process only first half of threads in each block
 // This is safe because threadIdx.x 0-15 in warp 0 will all take same path
 if (blockIdx.x % 2 == 0) {
 data[idx] = data[idx] * 2.0f;
 } else {
 data[idx] = data[idx] * 3.0f;
 }
 }
}

// ============================================
// MAIN FUNCTION: Demonstrates All Kernel Launches
// ============================================
int main() {
 const int N = 1024 * 1024; // 1 million elements
 const int WIDTH = 1024;
 const int HEIGHT = 1024;
 const int DEPTH = 64;

 // Allocate host memory
 float *h_data = (float*)malloc(N * sizeof(float));
 float *h_matrix = (float*)malloc(WIDTH * HEIGHT * sizeof(float));
 float *h_volume = (float*)malloc(WIDTH * HEIGHT * DEPTH * sizeof(float));

 // Initialize data
 for (int i = 0; i < N; i++) {
 h_data[i] = (float)i;
 }

 // Allocate device memory
 float *d_data, *d_matrix, *d_volume;
 CUDA_CHECK(cudaMalloc(&d_data, N * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_matrix, WIDTH * HEIGHT * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_volume, WIDTH * HEIGHT * DEPTH * sizeof(float)));

 // Copy data to device
 CUDA_CHECK(cudaMemcpy(d_data, h_data, N * sizeof(float), cudaMemcpyHostToDevice));

 // ============================================
 // 1D Kernel Launch Configuration
 // ============================================
 int blockSize = 256; // Threads per block (multiple of 32)
 int gridSize = (N + blockSize - 1) / blockSize; // Ceiling division

 printf("Launching 1D kernel: %d blocks x %d threads\n", gridSize, blockSize);
 kernel_double_array_1d<<<gridSize, blockSize>>>(d_data, N);

 // ============================================
 // 2D Kernel Launch Configuration
 // ============================================
 dim3 blockDim2d(16, 16); // 256 threads per block
 dim3 gridDim2d((WIDTH + 15) / 16, (HEIGHT + 15) / 16);

 printf("Launching 2D kernel: (%d x %d) blocks x (%d x %d) threads\n",
 gridDim2d.x, gridDim2d.y, blockDim2d.x, blockDim2d.y);
 kernel_process_matrix_2d<<<gridDim2d, blockDim2d>>>(d_matrix, WIDTH, HEIGHT);

 // ============================================
 // 3D Kernel Launch Configuration
 // ============================================
 dim3 blockDim3d(8, 8, 8); // 512 threads per block
 dim3 gridDim3d((WIDTH + 7) / 8, (HEIGHT + 7) / 8, (DEPTH + 7) / 8);

 printf("Launching 3D kernel: (%d x %d x %d) blocks x (%d x %d x %d) threads\n",
 gridDim3d.x, gridDim3d.y, gridDim3d.z,
 blockDim3d.x, blockDim3d.y, blockDim3d.z);
 kernel_process_volume_3d<<<gridDim3d, blockDim3d>>>(d_volume, WIDTH, HEIGHT, DEPTH);

 // ============================================
 // Grid-Stride Loop Launch
 // ============================================
 int smallGridSize = 64; // Even with fewer blocks, grid-stride works
 printf("Launching grid-stride kernel: %d blocks x %d threads\n", 
 smallGridSize, blockSize);
 kernel_grid_stride_loop<<<smallGridSize, blockSize>>>(d_data, N);

 // Wait for kernels to complete
 CUDA_CHECK(cudaDeviceSynchronize());

 printf("All kernels completed successfully!\n");

 // Free memory
 free(h_data);
 free(h_matrix);
 free(h_volume);
 cudaFree(d_data);
 cudaFree(d_matrix);
 cudaFree(d_volume);

 return 0;
}

