// ============================================
// WARP SHUFFLE: Intra-Warp Data Exchange
// ============================================
// __shfl_sync allows threads in a warp to exchange data directly
// from their registers without using shared memory

__device__ void warp_shuffle_demo(float *result) {
 // Each thread has its own value
 float value = (float)threadIdx.x;

 // Get value from another thread in the warp
 // This moves data from thread 'source' to all other threads
 int source = (threadIdx.x + 16) % 32; // Thread exchanges with opposite half

 // __shfl_sync(mask, var, src_lane, width)
 // src_lane: which lane to read from (0-31)
 // width: can be 8, 16, or 32 (sub-warp shuffle)
 float shuffled = __shfl_sync(0xFFFFFFFF, value, source, 32);

 // Now 'shuffled' contains the value from 'source' thread
 if (threadIdx.x == 0) {
 *result = shuffled;
 }
}

// ============================================
// WARP REDUCTION: Efficient Parallel Reduction
// ============================================
__device__ float warp_reduce_sum(float val) {
 // Each thread starts with its value
 // Perform reduction within the warp

 // Add thread 0 and 1, then 0-3, etc.
 // __shfl_down: gets value from 'delta' lanes ahead
 val += __shfl_down_sync(0xFFFFFFFF, val, 16);
 val += __shfl_down_sync(0xFFFFFFFF, val, 8);
 val += __shfl_down_sync(0xFFFFFFFF, val, 4);
 val += __shfl_down_sync(0xFFFFFFFF, val, 2);
 val += __shfl_down_sync(0xFFFFFFFF, val, 1);

 // Result is now in all threads (replicated)
 return val;
}

// ============================================
// WARP BALLOT: Collect Per-Thread Information
// ============================================
__device__ void warp_ballot_demo(int *results) {
 // Each thread has a predicate
 bool predicate = (threadIdx.x % 2 == 0);

 // __ballot_sync: returns 32-bit mask with 1 bit per thread
 // Bit i is set if thread i's predicate is true
 unsigned int mask = __ballot_sync(0xFFFFFFFF, predicate);

 // __popcount: count number of 1 bits
 int true_count = __popc(mask);

 // Store results (only thread 0 writes to avoid race)
 if (threadIdx.x == 0) {
 results[0] = true_count;
 results[1] = __popc(__ballot_sync(0xFFFFFFFF, !predicate));
 }
}

// ============================================
// WARP ANY/ALL: Predicate Testing
// ============================================
__device__ void warp_any_all_demo(bool *results) {
 bool my_flag = (threadIdx.x < 16); // First half of warp

 // __any_sync: returns true if ANY thread in warp has predicate true
 bool any_result = __any_sync(0xFFFFFFFF, my_flag);

 // __all_sync: returns true if ALL threads in warp have predicate true
 bool all_result = __all_sync(0xFFFFFFFF, my_flag);

 if (threadIdx.x == 0) {
 results[0] = any_result; // Should be true
 results[1] = all_result; // Should be false (not all have flag)
 }
}

// ============================================
// BLOCK SYNCHRONIZATION: __syncthreads()
// ============================================
__global__ void kernel_with_sync(float *global_data, int N) {
 // Allocate shared memory for block-level data
 __shared__ float shared_data[256];

 int tid = threadIdx.x;
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Phase 1: Each thread loads data
 if (idx < N) {
 shared_data[tid] = global_data[idx];
 } else {
 shared_data[tid] = 0.0f;
 }

 // CRITICAL: Synchronize all threads in block
 // All threads must reach this point before any can proceed
 __syncthreads();

 // Phase 2: Parallel reduction in shared memory
 // Simple example: sum reduction
 for (int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 shared_data[tid] += shared_data[tid + s];
 }
 // Sync after each reduction step
 __syncthreads();
 }

 // Phase 3: Write result (only thread 0)
 if (tid == 0) {
 global_data[blockIdx.x] = shared_data[0];
 }
}

// ============================================
// VOLATILE QUALIFIER: Important for Correctness
// ============================================
// The volatile qualifier prevents the compiler from caching
// values in registers, ensuring memory writes are visible

__global__ void kernel_volatile_example(volatile float *data) {
 int tid = threadIdx.x;

 // Without volatile, compiler might keep value in register
 // and other threads won't see the update immediately
 data[tid] = (float)tid;

 // Memory fence ensures ordering of memory operations
 __threadfence();
}

