// MAIN: Demonstrate Warp and Block Operations
// ============================================
int main() {
 printf("CUDA Warp and Block Operations Demo\n");
 printf("====================================\n\n");

 // Get device properties
 int deviceId;
 cudaGetDevice(&deviceId);
 cudaDeviceProp prop;
 cudaGetDeviceProperties(&prop, deviceId);

 printf("Device: %s\n", prop.name);
 printf("Warp Size: %d\n", prop.warpSize);
 printf("Max Threads Per Block: %d\n", prop.maxThreadsPerBlock);
 printf("Max Threads Per SM: %d\n", prop.maxThreadsPerMultiProcessor);

 // Test kernel with synchronization
 const int N = 1024;
 float *d_data;
 cudaMalloc(&d_data, N * sizeof(float));

 // Initialize data
 float *h_data = new float[N];
 for (int i = 0; i < N; i++) h_data[i] = 1.0f;
 cudaMemcpy(d_data, h_data, N * sizeof(float), cudaMemcpyHostToDevice);

 // Launch kernel with synchronization
 int blockSize = 256;
 int gridSize = (N + blockSize - 1) / blockSize;
 kernel_with_sync<<<gridSize, blockSize>>>(d_data, N);

 cudaDeviceSynchronize();

 // Copy back and verify
 cudaMemcpy(h_data, d_data, sizeof(float) * gridSize, cudaMemcpyDeviceToHost);

 printf("\nReduction results (first few blocks):\n");
 for (int i = 0; i < min(4, gridSize); i++) {
 printf(" Block %d sum: %.0f\n", i, h_data[i]);
 }

 delete[] h_data;
 cudaFree(d_data);

 printf("\nDemo completed!\n");

 return 0;
}
